 1	import type { FC } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  Flex,
 7	  FlexItem,
 8	  HelperText,
 9	  HelperTextItem,
10	} from '@patternfly/react-core';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	import './PlanMappingsActionsBar.scss';
14	
15	type PlanMappingsActionsBarProps = {
16	  isLoading: boolean;
17	  dataChanged: boolean;
18	  reset: (preserveUpdated?: boolean) => void;
19	  onUpdate: () => void;
20	};
21	
22	const PlanMappingsActionsBar: FC<PlanMappingsActionsBarProps> = ({
23	  dataChanged,
24	  isLoading,
25	  onUpdate,
26	  reset,
27	}) => {
28	  const { t } = useForkliftTranslation();
29	  return (
30	    <>
31	      <Flex>
32	        <FlexItem>
33	          <Button
34	            variant={ButtonVariant.primary}
35	            onClick={onUpdate}
36	            isDisabled={!dataChanged}
37	            isLoading={isLoading}
38	            data-testid="update-mappings-button"
39	          >
40	            {t('Update mappings')}
41	          </Button>
42	        </FlexItem>
43	        <FlexItem>
44	          <Button
45	            variant={ButtonVariant.secondary}
46	            onClick={() => {
47	              reset();
48	            }}
49	            data-testid="cancel-mappings-button"
50	          >
51	            {t('Cancel')}
52	          </Button>
53	        </FlexItem>
54	      </Flex>
55	      <HelperText className="forklift-plan-mappings-actions-bar__helper-text">
56	        <HelperTextItem variant="indeterminate">
57	          {t(
58	            'Click the update mappings button to save your changes, button is disabled until a change is detected.',
59	          )}
60	        </HelperTextItem>
61	      </HelperText>
62	    </>
63	  );
64	};
65	
66	export default PlanMappingsActionsBar;

